sql:
SELECT AVG(a.read_time_minutes) AS avg_read_time, AVG(m.fog_index) AS avg_fog_index
FROM articles a
INNER JOIN metrics m ON a.article_id = m.article_id;

SELECT COUNT(*) 
FROM articles 
WHERE publication_date > '2022-01-01';

SELECT AVG(flesch_reading_ease) AS average_readability
FROM metrics
WHERE flesch_reading_ease > 50;

external_knowledge:
- "time travelers spend exploring" refers to the read time of articles;
- "English-speaking realm" means articles written in English;
- "embarked on their journey over a month ago" refers to articles accessed more than 30 days ago.
